  "content": "<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>MagicFX Prototype</title>
  <style>
    body {
      margin: 0;
      background: #111;
      color: white;
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      height: 100vh;
    }
    video, canvas {
      border: 2px solid #4ecdc4;
      border-radius: 10px;
      max-width: 100%;
    }
    .controls {
      margin-top: 20px;
      text-align: center;
    }
    button {
      background: #4ecdc4;
      color: black;
      border: none;
      padding: 10px 20px;
      font-weight: bold;
      border-radius: 5px;
      cursor: pointer;
      margin: 5px;
    }
  </style>
</head>
<body>

  <video id="video" width="640" height="480" autoplay muted></video>
  <canvas id="snapshot" width="640" height="480"></canvas>

  <div class="controls">
    <button id="capture">📸 Take Snapshot</button>
    <p id="instructions">Click the point on the object you want the animation to emit from.</p>
  </div>

  <script>
    const video = document.getElementById('video');
    const canvas = document.getElementById('snapshot');
    const ctx = canvas.getContext('2d');
    const captureBtn = document.getElementById('capture');
    const instructions = document.getElementById('instructions');

    let anchorPoint = null;

    async function initCamera() {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      video.srcObject = stream;
    }

    captureBtn.onclick = () => {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      instructions.textContent = 'Now tap the point on the object you want to track.';
    };

    canvas.onclick = (e) => {
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      anchorPoint = { x, y };

      // Visualize the point
      ctx.beginPath();
      ctx.arc(x, y, 6, 0, 2 * Math.PI);
      ctx.fillStyle = '#ff6b6b';
      ctx.fill();

      instructions.textContent = `Anchor point set at (${x.toFixed(0)}, ${y.toFixed(0)}). Next: Implement tracking.`;
    };

    initCamera();
  </script>
</body>
</html>"
}

