<body>
<div class="sidebar">
  <h2>Magic FX</h2>
  <div class="section-title">Select Effect</div>
  <div class="fx-grid" id="fxGrid"></div>

  <div class="section-title">Effect Controls</div>
  <label>Trail Duration</label>
  <input type="range" id="persistence" min="0.5" max="5" step="0.1" value="2">
  <label>Particle Size</label>
  <input type="range" id="size" min="2" max="20" value="8">
  <label>Intensity</label>
  <input type="range" id="intensity" min="1" max="10" value="5">
  <label>Gravity</label>
  <input type="range" id="gravity" min="0" max="2" step="0.1" value="0.5">

  <div class="section-title">Presets</div>
  <input type="text" id="presetName" placeholder="Preset name..." style="width: 100%; margin-bottom: 5px;">
  <button class="btn" id="savePreset">Save Preset</button>
  <div id="presetList"></div>

  <div class="section-title">Tracker</div>
  <button class="btn" id="scanObject">📸 Set Anchor Point</button>
  <p id="instructions">Click object in video to assign trail anchor.</p>

  <div class="section-title">Recording</div>
  <button class="btn" id="recordBtn">🔴 Start Recording</button>
</div>

<div class="main">
  <video id="video" width="640" height="480" autoplay muted></video>
  <canvas id="canvas" width="640" height="480"></canvas>
</div>

<script>
const video = document.getElementById('video');
const canvas = document.getElementById('canvas');
const ctx = canvas.getContext('2d');
const instructions = document.getElementById('instructions');
const fxGrid = document.getElementById('fxGrid');
const presetList = document.getElementById('presetList');

let currentFX = 'sparkles';
let model, selectedObject = null, anchorOffset = {x:0,y:0};
let particles = [], recording = false, mediaRecorder, recordedChunks = [];
let settings = { persistence: 2, size: 8, intensity: 5, gravity: 0.5 };

const updateSettings = () => {
  settings.persistence = parseFloat(document.getElementById('persistence').value);
  settings.size = parseInt(document.getElementById('size').value);
  settings.intensity = parseInt(document.getElementById('intensity').value);
  settings.gravity = parseFloat(document.getElementById('gravity').value);
};

const createParticle = (x, y) => ({
  x, y,
  vx: (Math.random() - 0.5) * 2,
  vy: (Math.random() - 0.5) * 2,
  life: 1,
  size: settings.size,
  fx: currentFX,
  color: `hsl(${Math.random() * 60 + 40}, 80%, 70%)`
});

const updateParticles = () => {
  particles = particles.filter(p => p.life > 0);
  particles.forEach(p => {
    p.x += p.vx;
    p.y += p.vy;
    p.vy += settings.gravity * 0.1;
    p.life -= 0.01 / settings.persistence;
  });
};

const drawParticles = () => {
  particles.forEach(p => {
    ctx.globalAlpha = p.life;
    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
    ctx.fill();
    ctx.globalAlpha = 1;
  });
};

const buildFXGrid = () => {
  const types = ['sparkles','fire','water','lightning','smoke','stars','rainbow','magic'];
  types.forEach(fx => {
    const item = document.createElement('div');
    item.className = 'fx-item';
    if (fx === currentFX) item.classList.add('active');
    item.innerText = fx;
    item.onclick = () => {
      document.querySelectorAll('.fx-item').forEach(i => i.classList.remove('active'));
      item.classList.add('active');
      currentFX = fx;
    };
    fxGrid.appendChild(item);
  });
};

const loadPresets = () => {
  presetList.innerHTML = '';
  const saved = JSON.parse(localStorage.getItem('fxPresets') || '[]');
  saved.forEach((p,i) => {
    const row = document.createElement('div');
    row.className = 'preset';
    row.innerHTML = `<span>${p.name}</span><span onclick="deletePreset(${i})">❌</span>`;
    row.querySelector('span').onclick = () => applyPreset(p);
    presetList.appendChild(row);
  });
};

const savePreset = () => {
  const name = document.getElementById('presetName').value.trim();
  if (!name) return;
  const newPreset = { name, ...settings, fx: currentFX };
  const all = JSON.parse(localStorage.getItem('fxPresets') || '[]');
  all.push(newPreset);
  localStorage.setItem('fxPresets', JSON.stringify(all));
  loadPresets();
};

const deletePreset = index => {
  const all = JSON.parse(localStorage.getItem('fxPresets') || '[]');
  all.splice(index,1);
  localStorage.setItem('fxPresets', JSON.stringify(all));
  loadPresets();
};

const applyPreset = p => {
  document.getElementById('persistence').value = p.persistence;
  document.getElementById('size').value = p.size;
  document.getElementById('intensity').value = p.intensity;
  document.getElementById('gravity').value = p.gravity;
  currentFX = p.fx;
  document.querySelectorAll('.fx-item').forEach(i => {
    i.classList.toggle('active', i.innerText === p.fx);
  });
  updateSettings();
};

const scanObject = async () => {
  instructions.textContent = 'Click video to assign trail anchor...';
  canvas.onclick = async e => {
    const r = canvas.getBoundingClientRect();
    const x = e.clientX - r.left;
    const y = e.clientY - r.top;
    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
    const predictions = await model.detect(canvas);
    selectedObject = predictions.find(p => {
      const [px, py, w, h] = p.bbox;
      return x >= px && x <= px + w && y >= py && y <= py + h;
    });
    if (selectedObject) {
      anchorOffset = { x: x - selectedObject.bbox[0], y: y - selectedObject.bbox[1] };
      instructions.textContent = `Tracking ${selectedObject.class}`;
    } else {
      instructions.textContent = 'No object found.';
    }
  };
};

const animate = async () => {
  ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
  updateSettings();

  if (model && selectedObject) {
    const predictions = await model.detect(video);
    const match = predictions.find(p => p.class === selectedObject.class);
    if (match) {
      const [x, y] = [match.bbox[0] + anchorOffset.x, match.bbox[1] + anchorOffset.y];
      for (let i = 0; i < settings.intensity; i++) {
        particles.push(createParticle(x, y));
      }
    }
  }

  updateParticles();
  drawParticles();
  requestAnimationFrame(animate);
};

const startRecording = () => {
  const stream = canvas.captureStream();
  mediaRecorder = new MediaRecorder(stream);
  mediaRecorder.ondataavailable = e => recordedChunks.push(e.data);
  mediaRecorder.onstop = () => {
    const blob = new Blob(recordedChunks, { type: 'video/webm' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'magic-fx-recording.webm';
    a.click();
  };
  recordedChunks = [];
  mediaRecorder.start();
};

const stopRecording = () => mediaRecorder.stop();

document.getElementById('savePreset').onclick = savePreset;
document.getElementById('scanObject').onclick = scanObject;
document.getElementById('recordBtn').onclick = () => {
  recording = !recording;
  document.getElementById('recordBtn').textContent = recording ? '⏹ Stop Recording' : '🔴 Start Recording';
  recording ? startRecording() : stopRecording();
};

(async () => {
  const stream = await navigator.mediaDevices.getUserMedia({ video: true });
  video.srcObject = stream;
  model = await cocoSsd.load();
  buildFXGrid();
  loadPresets();
  animate();
})();
</script>
