package com.sedona.verities.viewmodel

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.sedona.verities.data.Transaction
import com.sedona.verities.data.TransactionStatus
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

data class UiState(
    val transactions: List<Transaction> = emptyList(),
    val vigilanteMode: Boolean = false,
    val isLoading: Boolean = false,
    val lastSyncTime: Long? = null
)

class MainViewModel : ViewModel() {
    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    init {
        loadMockTransactions()
    }

    private fun loadMockTransactions() {
        val mockTransactions = listOf(
            Transaction("1", "Amazon Purchase", 45.99, TransactionStatus.PENDING),
            Transaction("2", "Savings Transfer", 200.00, TransactionStatus.VERIFIED),
            Transaction("3", "Investment Allocation", 150.00, TransactionStatus.CLEARED),
            Transaction("4", "Grocery Store", 78.45, TransactionStatus.PENDING),
            Transaction("5", "Utility Payment", 125.30, TransactionStatus.VERIFIED)
        )

        _uiState.value = _uiState.value.copy(transactions = mockTransactions)
    }

    fun toggleVigilanteMode() {
        _uiState.value = _uiState.value.copy(
            vigilanteMode = !_uiState.value.vigilanteMode
        )
    }

    fun approveTransaction(transaction: Transaction) {
        updateTransactionStatus(transaction.id, TransactionStatus.VERIFIED)
    }

    fun denyTransaction(transaction: Transaction) {
        removeTransaction(transaction.id)
    }

    fun flagTransaction(transaction: Transaction) {
        // Mark for manual review
        updateTransactionStatus(transaction.id, TransactionStatus.PENDING)
    }

    fun viewHistory() {
        // Placeholder for history functionality
    }

    fun syncData() {
        viewModelScope.launch {
            _uiState.value = _uiState.value.copy(isLoading = true)
            // Simulate sync operation
            kotlinx.coroutines.delay(1000)
            _uiState.value = _uiState.value.copy(
                isLoading = false,
                lastSyncTime = System.currentTimeMillis()
            )
        }
    }

    fun speakWithSedona(message: String) {
        // Voice assistant functionality handled in MainActivity
    }

    private fun updateTransactionStatus(id: String, status: TransactionStatus) {
        val updatedTransactions = _uiState.value.transactions.map { transaction ->
            if (transaction.id == id) {
                transaction.copy(status = status)
            } else {
                transaction
            }
        }
        _uiState.value = _uiState.value.copy(transactions = updatedTransactions)
    }

    private fun removeTransaction(id: String) {
        val updatedTransactions = _uiState.value.transactions.filter { it.id != id }
        _uiState.value = _uiState.value.copy(transactions = updatedTransactions)
    }
}

