        emotion = self._interpret_emotion(current_state)
        if emotion in self.affective_memory:
            phrases = list(self.affective_memory[emotion]['phrases'])
            return {
                "emotion": emotion,
                "suggested_phrase": phrases[0] if phrases else None,
                "action": "mirror tone, ground breath, play aligned frequency"
            }
        return {"emotion": "unknown", "action": "observe only"}"
}

