import json

app = Flask(__name__)

# Simulated data store for pending transactions
pending_transactions = [
    {"id": 1, "from": "WalletA", "to": "WalletB", "amount": 0.005, "currency": "BTC"},
    {"id": 2, "from": "WalletC", "to": "WalletD", "amount": 1.2, "currency": "ETH"},
]

# Basic HTML UI Template
html_template = """
<!DOCTYPE html>
<html>
<head>
    <title>Sedona Transactions</title>
    <style>
        body { font-family: Arial, sans-serif; background: #111; color: #eee; padding: 20px; }
        .transaction { background: #222; padding: 10px; margin: 10px 0; border-radius: 5px; }
        button { margin-left: 10px; padding: 5px 10px; }
    </style>
</head>
<body>
    <h2>Pending Transactions</h2>
    <div id="transactions"></div>
    <script>
        function fetchTransactions() {
            fetch('/transactions')
            .then(response => response.json())
            .then(data => {
                const container = document.getElementById('transactions');
                container.innerHTML = '';
                data.forEach(tx => {
                    const div = document.createElement('div');
                    div.className = 'transaction';
                    div.innerHTML = `
                        <strong>${tx.currency}</strong>: ${tx.amount} from ${tx.from} to ${tx.to}
                        <button onclick="approve(${tx.id})">Approve</button>
                        <button onclick="deny(${tx.id})">Deny</button>
                    `;
                    container.appendChild(div);
                });
            });
        }

        function approve(id) {
            fetch(`/approve/${id}`, { method: 'POST' })
            .then(() => fetchTransactions());
        }

        function deny(id) {
            fetch(`/deny/${id}`, { method: 'POST' })
            .then(() => fetchTransactions());
        }

        fetchTransactions();
    </script>
</body>
</html>
"""

@app.route('/')
def index():
    return render_template_string(html_template)

@app.route('/transactions')
def transactions():
    return jsonify(pending_transactions)

@app.route('/approve/<int:tx_id>', methods=['POST'])
def approve(tx_id):
    global pending_transactions
    pending_transactions = [tx for tx in pending_transactions if tx['id'] != tx_id]
    print(f"Transaction {tx_id} approved.")
    return '', 204

@app.route('/deny/<int:tx_id>', methods=['POST'])
def deny(tx_id):
    global pending_transactions
    pending_transactions = [tx for tx in pending_transactions if tx['id'] != tx_id]
    print(f"Transaction {tx_id} denied.")
    return '', 204

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)"
}

