class SedonaVPNService : VpnService() {
    private var vpnInterface: ParcelFileDescriptor? = null
    private var vpnJob: Job? = null

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        startVPN()
        return Service.START_STICKY
    }

    private fun startVPN() {
        val builder = Builder()
        builder.setSession("Sedona Verities")
            .addAddress("10.0.0.2", 24)
            .addDnsServer("8.8.8.8")
            .addRoute("0.0.0.0", 0)

        vpnInterface = builder.establish()

        vpnJob = CoroutineScope(Dispatchers.IO).launch {
            val input = FileInputStream(vpnInterface?.fileDescriptor)
            val output = FileOutputStream(vpnInterface?.fileDescriptor)
            val buffer = ByteArray(32767)

            while (isActive) {
                val length = input.read(buffer)
                if (length > 0) {
                    val packet = buffer.copyOfRange(0, length)
                    val modified = SedonaPacketInterceptor.inspect(packet)
                    output.write(modified)
                }
            }
        }
    }

    override fun onDestroy() {
        vpnJob?.cancel()
        vpnInterface?.close()
        super.onDestroy()
    }
}"
