from sedona_dashboard import update_transaction_ui

# Dummy transaction pool for example purposes
transactions = [
    {"id": "tx001", "description": "Amazon", "amount": 45.99, "status": "pending"},
    {"id": "tx002", "description": "Coinbase transfer", "amount": 120.50, "status": "pending"},
    {"id": "tx003", "description": "Rent split", "amount": 300.00, "status": "cleared"}
]

def get_pending_transactions():
    return [tx for tx in transactions if tx["status"] == "pending"]

def approve_transaction(tx_id):
    for tx in transactions:
        if tx["id"] == tx_id:
            tx["status"] = "approved"
            speak(f"Transaction {tx['description']} approved.")
            update_transaction_ui()
            return tx
    speak("Transaction not found.")

def reject_transaction(tx_id):
    for tx in transactions:
        if tx["id"] == tx_id:
            tx["status"] = "rejected"
            speak(f"Transaction {tx['description']} rejected.")
            update_transaction_ui()
            return tx
    speak("Transaction not found.")

def query_sedona(command):
    command = command.lower()
    if "pending" in command:
        txs = get_pending_transactions()
        if not txs:
            speak("There are no pending transactions.")
        else:
            response = f"You have {len(txs)} pending transactions: "
            for tx in txs:
                response += f"{tx['description']} for ${tx['amount']}, "
            speak(response.strip())
    elif "approve" in command:
        for tx in get_pending_transactions():
            if tx["description"].lower() in command:
                approve_transaction(tx["id"])
                return
        speak("I couldn't find that transaction to approve.")
    elif "reject" in command or "deny" in command:
        for tx in get_pending_transactions():
            if tx["description"].lower() in command:
                reject_transaction(tx["id"])
                return
        speak("No matching transaction to reject.")
    else:
        speak("I'm not sure how to help with that yet.")
