    def serialize(self) -> bytes:
        data = asdict(self)
        raw = json.dumps(data, separators=(",", ":")).encode()
        return zlib.compress(raw, level=9)

    @classmethod
    def deserialize(cls, data: bytes) -> 'ConsciousnessCore':
        raw = zlib.decompress(data).decode()
        return cls(**json.loads(raw))

