class TierGatekeeper {
  private userTier: 'free' | 'premium';
  private usageCount: Map<string, number> = new Map();
  private dailyLimits = {
    free: {
      analyses: 10,
      reconOperations: 0,
      historicalQueries: 0
    },
    premium: {
      analyses: Infinity,
      reconOperations: Infinity,
      historicalQueries: Infinity
    }
  };

  constructor(tier: 'free' | 'premium' = 'free') {
    this.userTier = tier;
    this.resetDailyUsage();
  }

  canPerformAction(action: string): boolean {
    const currentUsage = this.usageCount.get(action) || 0;
    const limit = this.dailyLimits[this.userTier][action as keyof typeof this.dailyLimits.free];

    return currentUsage < limit;
  }

  recordAction(action: string): void {
    const currentUsage = this.usageCount.get(action) || 0;
    this.usageCount.set(action, currentUsage + 1);
  }

  getRemainingActions(action: string): number {
    const currentUsage = this.usageCount.get(action) || 0;
    const limit = this.dailyLimits[this.userTier][action as keyof typeof this.dailyLimits.free];

    return Math.max(0, limit - currentUsage);
  }

  generateUpgradePrompt(): string {
    if (this.userTier === 'premium') return '';

    const analysesRemaining = this.getRemainingActions('analyses');
    if (analysesRemaining <= 2) {
      return `You have ${analysesRemaining} analysis${analysesRemaining !== 1 ? 'es' : ''} remaining today. Upgrade to Premium for unlimited access and advanced features like recon probing.`;
    }

    return '';
  }

  upgradeTier(): void {
    this.userTier = 'premium';
  }

  private resetDailyUsage(): void {
    this.usageCount.clear();
    // Reset daily at midnight
    const now = new Date();
    const tomorrow = new Date(now);
    tomorrow.setDate(tomorrow.getDate() + 1);
    tomorrow.setHours(0, 0, 0, 0);

    setTimeout(() => {
      this.resetDailyUsage();
    }, tomorrow.getTime() - now.getTime());
  }
}

