    if (this.tier === 'premium') {
      this.transactionHistory.push(transaction);
      this.updateLearningData(transaction);
      this.saveData();
    }
  }

  getTransactionHistory(): BlockchainTransaction[] {
    if (this.tier === 'free') {
      throw new Error("Transaction history requires Premium tier");
    }
    return [...this.transactionHistory];
  }

  private updateLearningData(transaction: BlockchainTransaction): void {
    const hour = new Date(transaction.timestamp).getHours();
    const value = parseFloat(transaction.value);

    // Update time preferences
    if (!this.learningData.timePreferences) {
      this.learningData.timePreferences = new Array(24).fill(0);
    }
    this.learningData.timePreferences[hour]++;

    // Update value patterns
    if (!this.learningData.valuePatterns) {
      this.learningData.valuePatterns = [];
    }
    this.learningData.valuePatterns.push(value);

    // Keep only recent data (last 1000 transactions)
    if (this.learningData.valuePatterns.length > 1000) {
      this.learningData.valuePatterns = this.learningData.valuePatterns.slice(-1000);
    }
  }

  getPersonalizedRecommendations(): string[] {
    if (this.tier === 'free') {
      return ["Upgrade to Premium for personalized recommendations"];
    }

    const recommendations: string[] = [];

    // Analyze time patterns
    if (this.learningData.timePreferences) {
      const peakHour = this.learningData.timePreferences.indexOf(Math.max(...this.learningData.timePreferences));
      const currentHour = new Date().getHours();

      if (Math.abs(currentHour - peakHour) > 3) {
        recommendations.push(`You typically transact around ${peakHour}:00. Consider waiting for better gas prices.`);
      }
    }

    // Analyze value patterns
    if (this.learningData.valuePatterns && this.learningData.valuePatterns.length > 10) {
      const avgValue = this.learningData.valuePatterns.reduce((sum: number, val: number) => sum + val, 0) / this.learningData.valuePatterns.length;
      recommendations.push(`Your average transaction value is ${avgValue.toFixed(4)} ETH`);
    }

    return recommendations;
  }

  private loadStoredData(): void {
    // In a real implementation, this would load from local storage
    // For demo purposes, we'll simulate some existing data
    this.learningData = {
      timePreferences: new Array(24).fill(0).map(() => Math.floor(Math.random() * 10)),
      valuePatterns: Array.from({length: 50}, () => Math.random() * 0.5)
    };
  }

  private saveData(): void {
    // In a real implementation, this would save to local storage
    // For demo purposes, we'll just log the action
    console.log('Data saved to local storage');
  }

  exportData(): any {
    if (this.tier === 'free') {
      throw new Error("Data export requires Premium tier");
    }

    return {
      preferences: this.preferences,
      transactionHistory: this.transactionHistory,
      learningData: this.learningData,
      exportDate: new Date().toISOString()
    };
  }
}

// ================================================================
// LUCID SYNC LAYER
// ================================================================

class LucidSyncLayer {
  private syncEnabled: boolean = true;
  private lastSyncTime: number = 0;
  private syncInterval: number = 24 * 60 * 60 * 1000; // 24 hours

  async checkForUpdates(): Promise<any> {
    if (!this.syncEnabled) return null;

    const now = Date.now();
    if (now - this.lastSyncTime < this.syncInterval) {
      return null; // Too soon for next sync
    }

    // Simulate checking for updates
    const updates = {
      version: "1.2.3",
      patches: [
        "Improved gas estimation accuracy",
        "Enhanced security for recon operations",
        "New pattern recognition algorithms"
      ],
      criticalUpdate: false,
      downloadUrl: "https://lucid.ai/sedona/updates"
    };

    this.lastSyncTime = now;
    return Math.random() > 0.7 ? updates : null; // 30% chance of updates
  }

  async sendTelemetry(data: any): Promise<void> {
    if (!this.syncEnabled) return;

    // Only send anonymized usage statistics
    const telemetryData = {
      version: "1.0.0",
      usage: {
        dailyAnalyses: data.analyses || 0,
        tier: data.tier || 'free',
        features: data.features || []
      },
      performance: {
        avgResponseTime: data.responseTime || 0,
        errorRate: data.errorRate || 0
      },
      timestamp: Date.now()
    };

    // Simulate sending telemetry
    console.log('Telemetry sent:', telemetryData);
  }

  setSyncEnabled(enabled: boolean): void {
    this.syncEnabled = enabled;
  }

  getSyncStatus(): any {
    return {
      enabled: this.syncEnabled,
      lastSync: new Date(this.lastSyncTime).toISOString(),
      nextSync: new Date(this.lastSyncTime + this.syncInterval).toISOString()
    };
  }
}

